if doc.workflow_state == "Job File Initiated":

    customer_name = doc.customer or ""

    # prevent duplicate for same job file
    existing = frappe.db.exists(
        "Whatsapp Broadcast Queue",
        {
            "reference_name": doc.name,
            "event_key": "job_file_initiated"
        }
    )

    if not existing:

        message = f"""
{{
    "name": "{customer_name}",
    "text": "Dear {customer_name}, Your Case is initiated"
}}
"""

        queue = frappe.new_doc("Whatsapp Broadcast Queue")

        queue.party = "Customer"
        queue.dynamic_link_uzxz = customer_name

        queue.event_key = "job_file_initiated"
        queue.reference_doctype = doc.doctype
        queue.reference_name = doc.name

        queue.message = message
        queue.message_status = "Pending"
        queue.send_on = frappe.utils.now_datetime()

        # child table row
        queue.append("custom_variables", {
            "variable_name": "name",
            "variable_value": customer_name
        })

        queue.insert(ignore_permissions=True)
